import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer/src/core';

export class GatherProgressParser implements IMessageParser {
    private _duration: number = 0;

    public flush(): boolean {
        this._duration = 0;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        this._duration = wrapper.readInt();
        return true;
    }

    public get duration(): number {
        return this._duration;
    }
}
